        goto err;

    if (cms->d.data->length > EVP_CIPHER_block_size(ctx->cipher)) {
        if (ctx->cipher->flags & EVP_CIPH_FLAG_WRAP_ALLOW) {
            if (!cms_p7decrypt_wrap_set(ctx))
