                   CMS_R_PKCS7_LENGTH_IS_NOT_MODULUS_OF_BLOCK_LENGTH);
            goto err;
        }
    }

    cms->d.data->ctx = ctx;
    rv = 0;
 err:
    EVP_CIPHER_CTX_free(ctx);
    return rv;
}
