static int cms_p7decrypt_setctx(CMS_ContentInfo *cms, EVP_CIPHER_CTX *ctx,
                               int decrypt)
{
    int rv = -1;
    PKCS7 *p7 = cms->d.data->p7;
    PKCS7_ENVELOPE *envelope = p7->d.envelopedData->envelopes->d.envelope;
    PKCS7_ISSUER_AND_SERIAL *ias;
    X509 *x509 = NULL;
    EVP_PKEY *pkey = NULL;
    CMS_RecipientInfo *ri = cms->d.data->ri;

    ias = ri->issuer_and_serial;
    x509 = cms_ri_get0_peer(ri);
    if (x509 == NULL) {
        CMSerr(CMS_F_CMS_P7DECRYPT_SETCTX,
               CMS_R_NO_PEER_CERTIFICATE_FOUND);
        goto err;
    }
    pkey = cms_ri_get0_key(ri);
    if (pkey == NULL) {
        CMSerr(CMS_F_CMS_P7DECRYPT_SETCTX,
               CMS_R_NO_PRIVATE_KEY_FOUND);
        goto err;
    }

    if (cms->d.data->key_info) {
        rv = cms_key_info_decrypt(cms->d.data->key_info,
                                   envelope->encryptedKey,
                                   envelope->encryptedKey->length,
                                   cms->d.data->key,
                                   cms->d.data->keylen);
        if (rv <= 0)
            goto err;
    }

    if (decrypt) {
        CMSerr(CMS_F_CMS_P7DECRYPT_SETCTX,
               CMS_R_PKCS7_DECRYPT_INIT_ERROR);
        goto err;
    }

    rv = cms_set1_cmskey(cms, p7, ias, x509, pkey,
                         CMS_KEYTYPE_ENCRYPTED | CMS_KEYTYPE_ENCRYPTED_DIGEST,
                         CMS_ENCRYPTED_DATA_ENCRYPTED_KEY, ctx, 1);
    if (rv <= 0)
        goto err;

    if (ctx->cipher->flags & EVP_CIPH_FLAG_WRAP_ALLOW)
        cms->d.data->cmskey = cms->d.data->key;

    rv = 0;
 err:
    X509_free(x509);
    EVP_PKEY_free(pkey);
    return rv;
}
