static int cms_p7decrypt_wrap_set(EVP_CIPHER_CTX *ctx)
{
    int rv = -1;
    unsigned char *iv;
    unsigned int iv_len;
    int i;

    iv = EVP_CIPHER_CTX_iv(ctx);
    iv_len = EVP_CIPHER_iv_length(ctx->cipher);
    if (iv_len == 0)
        iv_len = EVP_CIPHER_block_size(ctx->cipher);

    if (ctx->cipher->nid == NID_aes_256_cbc ||
        ctx->cipher->nid == NID_aes_192_cbc ||
        ctx->cipher->nid == NID_aes_128_cbc) {
        unsigned char *ivp;
        unsigned int ivp_len;

        ivp = EVP_CIPHER_CTX_rand_key(ctx);
        ivp_len = EVP_CIPHER_block_size(ctx->cipher);
        if (ivp_len == 0)
            ivp_len = EVP_CIPHER_iv_length(ctx->cipher);

        if (ivp_len > EVP_CIPHER_block_size(ctx->cipher))
            ivp_len = EVP_CIPHER_block_size(ctx->cipher);

        if (ivp == NULL) {
            CMSerr(CMS_F_CMS_P7DECRYPT_WRAP_SET,
                   CMS_R_PKCS7_ENCRYPTED_KEY_IV_ERROR);
            goto err;
        }

        memcpy(iv, ivp, ivp_len);
        for (i = ivp_len; i < iv_len; i++)
            iv[i] = 0;
        iv_len = ivp_len;
    } else if (ctx->cipher->nid == NID_aes_256_gcm ||
               ctx->cipher->nid == NID_aes_192_gcm ||
               ctx->cipher->nid == NID_aes_128_gcm) {
        iv_len = EVP_CIPHER_block_size(ctx->cipher);
    } else if (ctx->cipher->nid == NID_aes_256_ccm ||
               ctx->cipher->nid == NID_aes_192_ccm ||
               ctx->cipher->nid == NID_aes_128_ccm) {
        iv_len = EVP_CIPHER_block_size(ctx->cipher);
    } else {
        CMSerr(CMS_F_CMS_P7DECRYPT_WRAP_SET,
               CMS_R_PKCS7_ENCRYPTED_KEY_IV_ERROR);
        goto err;
    }

    if (ctx->cipher->flags & EVP_CIPH_FLAG_WRAP_ALLOW)
        ctx->wrap_ctx = EVP_CIPHER_CTX_new();
    if (ctx->cipher->flags & EVP_CIPH_FLAG_WRAP_ALLOW &&
        ctx->wrap_ctx == NULL) {
        CMSerr(CMS_F_CMS_P7DECRYPT_WRAP_SET,
               ERR_R_MALLOC_FAILURE);
        goto err;
    }

    if (ctx->cipher->flags & EVP_CIPH_FLAG_WRAP_ALLOW) {
        EVP_CIPHER_CTX_set_flags(ctx->wrap_ctx,
                                 EVP_CIPHER_CTX_flags(ctx));
        EVP_CIPHER_CTX_set_cipher(ctx->wrap_ctx, ctx->cipher);
        EVP_CIPHER_CTX_set_pkey(ctx->wrap_ctx, ctx->pkey);
        EVP_CIPHER_CTX_set_evp_data(ctx->wrap_ctx, ctx->evp_data);
        EVP_CIPHER_CTX_set_iv(ctx->wrap_ctx, iv, iv_len);
    }

    rv = 0;
 err:
    return rv;
}
