```
int cms_RecipientInfo_ktri_encrypt(cms_RecipientInfo *ri,
                                   EVP_CIPHER *cipher,
                                   const unsigned char *key,
                                   int keylen,
                                   int flags)
{
    EVP_PKEY_CTX *pkctx = NULL;
    unsigned char *out = NULL;
    int outlen = 0;
    int rv = 0;
    const EVP_CIPHER *ciph;
    int ciphlen;

    if (keylen != EVP_CIPHER_key_length(cipher))
        return 0;

    ciph = EVP_CIPHER_CTX_cipher(ri->enc_ctx);
    ciphlen = EVP_CIPHER_block_size(ciph);

    if (ciphlen != 1)
        return 0;

    if (ri->enc_ctx == NULL)
        ri->enc_ctx = EVP_CIPHER_CTX_new();
    else if (!EVP_CIPHER_CTX_reset(ri->enc_ctx))
        return 0;

    pkctx = ri->pkctx;
    if (pkctx == NULL)
        return 0;

    if (!EVP_PKEY_encrypt_init(pkctx))
        return 0;

    if (EVP_PKEY_CTX_ctrl(pkctx, EVP_PKEY_CTX_get0_pkeytype(pkctx),
                           EVP_PKEY_CTRL_PKCS7_ENCRYPT,
                           (int)CMS_USE_KEYID, ri->rid, NULL) <= 0)
        return 0;

    if (!EVP_PKEY_encrypt(pkctx, NULL, &outlen, key, keylen))
        return 0;

    out = OPENSSL_malloc(outlen);
    if (out == NULL)
        return 0;

    if (!EVP_PKEY_encrypt(pkctx, out, &outlen, key, keylen))
        goto err;

    if (!CMS_RecipientInfo_set0_key(ri, out, outlen, flags))
        goto err;

    rv = 1;

 err:

    if (out != NULL)
        OPENSSL_free(out);

    return rv;
}
