        return 1;
    ret = X509_policy_check(&ct->tree, &ct->eplicit_policy, ct->chain,
                            ct->param->policies, ct->param->flags);
    if (ret == 0) {
        X509err(X509_F_CHECK_POLICY, ERR_R_MALLOC_FAILURE);
        return 0;
