    if (!hService)
    {
        DWORD dwError = GetLastError();
        LogError(L"OpenServiceW failed: %lu", dwError);
        return HRESULT_FROM_WIN32(dwError);
    }

    DWORD dwServiceType = 0;
    DWORD dwCurrentStartType = 0;
    DWORD dwCurrentErrorControl = 0;
    DWORD dwCurrentLoadOrderGroup = 0;
    DWORD dwCurrentTagId = 0;
    DWORD dwCurrentDependencies = 0;
    DWORD dwCurrentServiceStartName = 0;
    DWORD dwCurrentDisplayName = 0;

    if (!QueryServiceConfigW(
        hService,
        &dwServiceType,
        &dwCurrentStartType,
        &dwCurrentErrorControl,
        &dwCurrentLoadOrderGroup,
        &dwCurrentTagId,
        &dwCurrentDependencies,
        &dwCurrentServiceStartName,
        &dwCurrentDisplayName))
    {
        DWORD dwError = GetLastError();
        LogError(L"QueryServiceConfigW failed: %lu", dwError);
        CloseServiceHandle(hService);
        return HRESULT_FROM_WIN32(dwError);
    }

    if (!ChangeServiceConfigW(
        hService,
        dwServiceType,
        startType,
        dwCurrentErrorControl,
        dwCurrentLoadOrderGroup,
        nullptr,
        nullptr,
        nullptr,
        nullptr,
        nullptr,
        nullptr,
        nullptr))
    {
        DWORD dwError = GetLastError();
        LogError(L"ChangeServiceConfigW failed: %lu", dwError);
        CloseServiceHandle(hService);
        return HRESULT_FROM_WIN32(dwError);
    }

    CloseServiceHandle(hService);

    return S_OK;
