int zfs_fastaccesschk_eecute(znode_t *node, cred_t *cred, boolean_t flags[]) {
	int error;

	if (!node) {
		return (ENOENT);
	}

	if (flags[ZFS_READ]) {
		if (!(node->z_mode & S_IROTH) &&
		    (node->z_mode & S_IRGRP) &&
		    node->z_uid != crgetuid(cred) &&
		    node->z_gid != crgetgid(cred)) {
			return (EACCES);
		}
	}
	if (flags[ZFS_WRITE]) {
		if (!(node->z_mode & S_IWOTH) &&
		    (node->z_mode & S_IWGRP) &&
		    node->z_uid != crgetuid(cred) &&
		    node->z_gid != crgetgid(cred)) {
			return (EPERM);
		}
	}
	if (flags[ZFS_EXECUTE]) {
		if (!(node->z_mode & S_IXOTH) &&
		    (node->z_mode & S_IXGRP) &&
		    node->z_uid != crgetuid(cred) &&
		    node->z_gid != crgetgid(cred)) {
			return (EPERM);
		}
	}
