        cms->d.contained->d.encrypted->d.encryptedData->encryptedContentInfo = NULL;
    }
    if (CMS_get0_cms_ri(cms) == NULL) {
        CMSerr(CMS_F_CMS_SET1_CMS_RI, CMS_R_ERROR_SETTING_CONTENTINFO);
        return 0;
    }
    if (CMS_get0_cms_ri(cms)->d.encrypted->d.encryptedData->encryptedContentInfo != NULL)
        CMSerr(CMS_F_CMS_SET1_CMS_RI, CMS_R_ENCRYPTED_CONTENT_INFO_NOT_NULL);
    else {
        if (!(CMS_get0_cms_ri(cms)->d.encrypted->d.encryptedData->encryptedContentInfo =
              ASN1_item_new(ASN1_ITEM_rptr(CMS_EncryptedContentInfo)))) {
            CMSerr(CMS_F_CMS_SET1_CMS_RI, ERR_R_MALLOC_FAILURE);
            return 0;
        }
    }
    encinfo = ASN1_item_new(ASN1_ITEM_rptr(ASN1_OCTET_STRING));
    if (encinfo == NULL) {
        CMSerr(CMS_F_CMS_SET1_CMS_RI, ERR_R_MALLOC_FAILURE);
        return 0;
    }
    CMS_get0_cms_ri(cms)->d.encrypted->d.encryptedData->encryptedContent =
        encinfo;
    CMS_get0_cms_ri(cms)->d.encrypted->d.encryptedData->encryptedContentInfo->content = encinfo;
    CMS_get0_cms_ri(cms)->d.encrypted->d.encryptedData->encryptedContentInfo->contentType = OBJ_nid2obj(NID_pkcs7_data);
    CMS_get0_cms_ri(cms)->d.encrypted->d.encryptedData->encryptedContentInfo->cipher = CMS_get0_cipher(cms);
    for (i = 0; i < CMS_RecipientInfo_get_count(cms); i++) {
        ri = CMS_RecipientInfo_get0_ri(cms, i);
        if (CMS_RecipientInfo_set0_cms_ri(ri, cms) == 0) {
            CMSerr(CMS_F_CMS_SET1_CMS_RI, CMS_R_ERROR_SETTING_RECIPIENTINFO);
            return 0;
        }
    }
    return 1;
}
