static int check_suggestions(char_u *preword, char_u *word, int idx)
{
    char_u *s;
    int l;

    if (preword == NULL || *preword == NUL)
	return FALSE;

    l = (int)STRLEN(word);
    vim_strncpy(preword + l, word, (size_t)(l + 1));
    if (spell_check(preword, TRUE) != OK)
	return FALSE;

    s = spell_suggest[idx].word;
    if (s != NULL)
    {
	vim_strncpy(preword + l, s, (size_t)(l + 1));
	if (spell_check(preword, TRUE) != OK)
	    return FALSE;
    }
    return TRUE;
}

static int suggest_words(void)
