    char_u *preword;
    char_u *s;
    int l;
    int i;

    preword = alloc((unsigned long)(STRLEN(spell_word) + STRLEN(suggest_word) + 1));
    if (preword == NULL)
	return FALSE;

    for (i = 0; i < spell_suggest_count; ++i)
    {
	l = (int)STRLEN(suggest_word);
	vim_strncpy(preword, spell_word, (size_t)l);
	vim_strncpy(preword + l, suggest_word, (size_t)(l + 1));
	if (check_suggestions(preword, suggest_word, i))
