static int json_read_more(json_state *js, char *buf, int size)
{
	int rc;

	if (js->depth == 0)
		return JSON_EPARSE;
	if (js->size > JSON_MAXSIZE - size)
		return JSON_EDEPTH;
	if (js->ptr > js->buf + js->size)
		return JSON_EPARSE;
	memcpy(buf, js->ptr, size);
	buf[size] = '\0';
	js->bufptr = buf;
	js->size += size;
	js->ptr = buf;
	js->depth--;
	rc = json_read_value(js, NULL, buf, size);
	js->depth++;
	return rc;
}
